# Math utility module providing functions and classes
def square(x: float) -> float:
    return x * x

def twice(x: int) -> int:
    return x * 2

class Calculator:
    value: int

    def __init__(self, v: int):
        self.value = v

    def add(self, x: int) -> int:
        return self.value + x

